// Shared PDF builder for the export-report-pdf Edge Function. Pure
// function — takes the report + its transactions and returns the bytes
// of a PDF file. The watermark PNG is embedded as a base64 constant so
// there are no filesystem dependencies — the edge-runtime compiles to
// /var/tmp/... and can't resolve co-located asset files via
// import.meta.url.
//
// Layout — Letter (612 x 792 pt), 50pt margins. Each page paints:
//   1. The full-page watermark (logo PNG, low-alpha, centered)
//   2. The header band (logo + brand + generated-at)
//   3. The footer (page number + "Generated by Money Tracker")
//
// IMPORTANT: WinAnsi (Helvetica) only supports Windows-1252 chars.
// Do NOT use Unicode arrows — use ASCII alternatives.
import {
  PDFDocument,
  rgb,
  StandardFonts,
  type PDFFont,
} from "npm:pdf-lib@1.17.1";

// Embedded watermark — grayscale Money Tracker icon (1024x1024,
// alpha ~5-6%). Base64-encoded so the builder has zero fs deps.
const WATERMARK_B64 =
  "";
("");

// Colors from packages/frontend/src/index.css (rgb 0-1).
const PAGE_WIDTH = 612;
const PAGE_HEIGHT = 792;
const MARGIN_X = 50;
const MARGIN_Y = 50;
const COLOR_TEXT_PRIMARY = rgb(0.067, 0.094, 0.153); //        #111827
const COLOR_TEXT_SECONDARY = rgb(0.42, 0.45, 0.5); //           #6b7280
const COLOR_BORDER = rgb(0.85, 0.86, 0.87); //                 text-secondary/20
const COLOR_BG_SECONDARY = rgb(0.976, 0.98, 0.984); //         #f9fafb
const COLOR_HEADER_RULE = rgb(0.239, 0.353, 0.502); //         #3d5a80 button-primary
const COLOR_HEADER_BG = rgb(0.953, 0.965, 0.98); //           #3d5a80 at ~5% alpha
const COLOR_ACCENT = rgb(0.675, 0.98, 0.518); //              #acfa84 accent
const COLOR_ACCENT_BORDER = rgb(0.56, 0.82, 0.42); //          #acfa84 darkened for border
const COLOR_INCOME = rgb(0.027, 0.471, 0.341); //              emerald-700
const COLOR_EXPENSE = rgb(0.745, 0.071, 0.235); //             rose-700

let _watermarkRaw: Uint8Array | null = null;
function getWatermarkRaw(): Uint8Array | null {
  if (_watermarkRaw) return _watermarkRaw;
  try {
    _watermarkRaw = Uint8Array.from(atob(WATERMARK_B64), c => c.charCodeAt(0));
    return _watermarkRaw;
  } catch {
    return null;
  }
}

export interface PdfLabel {
  brand: string;
  reportLabel: string;
  summaryHeader: string;
  income: string;
  expenses: string;
  net: string;
  transactions: string;
  countSuffix: string;
  noTransactions: string;
  tableDate: string;
  tableMerchant: string;
  tableCategory: string;
  tableType: string;
  tableAmount: string;
  pageLabel: string;
  generatedBy: string;
  noDateRange: string;
}

export interface BuildReportPdfInput {
  report: {
    id: string;
    title: string;
    description: string | null;
    status: string;
    dateRangeStart: string | null;
    dateRangeEnd: string | null;
    createdAt: string;
    archivedAt: string | null;
  };
  transactions: Array<{
    id: string;
    name: string | null;
    merchant: string;
    amount: number;
    currency: string;
    transactionDate: string;
    category: string;
    transactionType: string;
  }>;
  perCurrency: Array<{
    currency: string;
    transactionCount: number;
    totalIncome: number;
    totalExpenses: number;
    net: number;
  }>;
  labels: PdfLabel;
  formatCurrency: (amount: number, currency: string) => string;
  formatDate: (date: string | null) => string;
}

export async function buildReportPdf(
  input: BuildReportPdfInput
): Promise<Uint8Array> {
  const {
    report,
    transactions,
    perCurrency,
    labels,
    formatCurrency,
    formatDate,
  } = input;
  const pdf = await PDFDocument.create();
  const helvetica = await pdf.embedFont(StandardFonts.Helvetica);
  const helveticaBold = await pdf.embedFont(StandardFonts.HelveticaBold);
  const raw = getWatermarkRaw();
  const watermark = raw ? await pdf.embedPng(raw) : null;

  const ctx: PdfContext = {
    pdf,
    helvetica,
    helveticaBold,
    watermark,
    labels,
    formatCurrency,
    formatDate,
    page: pdf.addPage([PAGE_WIDTH, PAGE_HEIGHT]),
    pageNumber: 1,
  };

  drawWatermark(ctx);
  drawHeaderBand(ctx);
  let cursorY = PAGE_HEIGHT - MARGIN_Y - 80;
  cursorY = drawTitleBlock(ctx, report, cursorY);
  cursorY = drawSummary(ctx, perCurrency, cursorY);
  cursorY = drawTransactionsTable(ctx, transactions, cursorY);
  drawFooter(ctx, cursorY);
  return await pdf.save();
}

// ─── layout primitives ────────────────────────────────────────────────

function drawWatermark(ctx: PdfContext): void {
  if (!ctx.watermark) return;
  const w = PAGE_WIDTH * 0.7;
  const h = w / (ctx.watermark.width / ctx.watermark.height);
  ctx.page.drawImage(ctx.watermark, {
    x: (PAGE_WIDTH - w) / 2,
    y: (PAGE_HEIGHT - h) / 2,
    width: w,
    height: h,
  });
}

function drawHeaderBand(ctx: PdfContext): void {
  const y = PAGE_HEIGHT - MARGIN_Y;
  // Light blue tint behind the header + title block
  ctx.page.drawRectangle({
    x: MARGIN_X - 10,
    y: y - 98,
    width: PAGE_WIDTH - 2 * MARGIN_X + 20,
    height: 124,
    color: COLOR_HEADER_BG,
  });
  ctx.page.drawLine({
    start: { x: MARGIN_X, y },
    end: { x: PAGE_WIDTH - MARGIN_X, y },
    thickness: 1,
    color: COLOR_HEADER_RULE,
  });
  ctx.page.drawText("Money Tracker", {
    x: MARGIN_X,
    y: y + 18,
    size: 14,
    font: ctx.helveticaBold,
    color: COLOR_TEXT_PRIMARY,
  });
  const dateStr = formatDateLocalized(new Date().toISOString(), ctx);
  const right = `${ctx.labels.reportLabel} \u00B7 ${dateStr}`;
  const rw = ctx.helvetica.widthOfTextAtSize(right, 10);
  ctx.page.drawText(right, {
    x: PAGE_WIDTH - MARGIN_X - rw,
    y: y + 22,
    size: 10,
    font: ctx.helvetica,
    color: COLOR_TEXT_SECONDARY,
  });
}

function drawTitleBlock(
  ctx: PdfContext,
  report: BuildReportPdfInput["report"],
  cursorY: number
): number {
  const { page, helveticaBold, helvetica } = ctx;
  page.drawText(report.title, {
    x: MARGIN_X,
    y: cursorY - 22,
    size: 22,
    font: helveticaBold,
    color: COLOR_TEXT_PRIMARY,
  });
  let y = cursorY - 22;
  if (report.description) {
    for (const line of wrapText(
      helvetica,
      report.description,
      PAGE_WIDTH - 2 * MARGIN_X - 80,
      11
    )) {
      page.drawText(line, {
        x: MARGIN_X,
        y: y - 11,
        size: 11,
        font: helvetica,
        color: COLOR_TEXT_SECONDARY,
      });
      y -= 14;
    }
  }
  const range = formatDateRange(report, ctx);
  if (range) {
    page.drawText(range, {
      x: MARGIN_X,
      y: y - 11,
      size: 10,
      font: helvetica,
      color: COLOR_TEXT_SECONDARY,
    });
    y -= 16;
  }
  return y - 8;
}

function drawSummary(
  ctx: PdfContext,
  perCurrency: BuildReportPdfInput["perCurrency"],
  cursorY: number
): number {
  const { page, helveticaBold, helvetica, formatCurrency, labels } = ctx;
  if (perCurrency.length === 0) {
    page.drawText(labels.noTransactions, {
      x: MARGIN_X,
      y: cursorY - 14,
      size: 11,
      font: helvetica,
      color: COLOR_TEXT_SECONDARY,
    });
    return cursorY - 26;
  }
  page.drawText(labels.summaryHeader, {
    x: MARGIN_X,
    y: cursorY - 12,
    size: 9,
    font: helvetica,
    color: COLOR_TEXT_SECONDARY,
  });
  let y = cursorY - 18;

  for (const bucket of perCurrency) {
    const bh = 56;
    if (y - bh < MARGIN_Y + 60) {
      ctx.page = ctx.pdf.addPage([PAGE_WIDTH, PAGE_HEIGHT]);
      ctx.pageNumber += 1;
      drawWatermark(ctx);
      drawHeaderBand(ctx);
      y = PAGE_HEIGHT - MARGIN_Y - 90;
    }
    const cardX = MARGIN_X;
    const cardY = y - bh;
    const cardW = PAGE_WIDTH - 2 * MARGIN_X;
    page.drawRectangle({
      x: cardX,
      y: cardY,
      width: cardW,
      height: bh,
      borderColor: COLOR_BORDER,
      borderWidth: 1,
      color: rgb(1, 1, 1),
    });
    // Green left accent bar
    page.drawRectangle({
      x: cardX,
      y: cardY,
      width: 3,
      height: bh,
      color: COLOR_ACCENT_BORDER,
    });
    page.drawText(bucket.currency, {
      x: cardX + 12,
      y: cardY + bh - 16,
      size: 10,
      font: helveticaBold,
      color: COLOR_TEXT_SECONDARY,
    });
    const ct = `${bucket.transactionCount} ${labels.countSuffix}`;
    page.drawText(ct, {
      x: cardX + cardW - 12 - helvetica.widthOfTextAtSize(ct, 9),
      y: cardY + bh - 16,
      size: 9,
      font: helvetica,
      color: COLOR_TEXT_SECONDARY,
    });
    page.drawText(labels.income, {
      x: cardX + 12,
      y: cardY + bh - 32,
      size: 11,
      font: helvetica,
      color: COLOR_TEXT_SECONDARY,
    });
    const inc = formatCurrency(bucket.totalIncome, bucket.currency);
    page.drawText(inc, {
      x: cardX + cardW - 12 - helveticaBold.widthOfTextAtSize(inc, 11),
      y: cardY + bh - 32,
      size: 11,
      font: helveticaBold,
      color: COLOR_INCOME,
    });
    page.drawText(labels.expenses, {
      x: cardX + 12,
      y: cardY + bh - 46,
      size: 11,
      font: helvetica,
      color: COLOR_TEXT_SECONDARY,
    });
    const exp = formatCurrency(bucket.totalExpenses, bucket.currency);
    page.drawText(exp, {
      x: cardX + cardW - 12 - helveticaBold.widthOfTextAtSize(exp, 11),
      y: cardY + bh - 46,
      size: 11,
      font: helveticaBold,
      color: COLOR_EXPENSE,
    });
    y -= bh + 8;
  }
  return y;
}

function drawTransactionsTable(
  ctx: PdfContext,
  transactions: BuildReportPdfInput["transactions"],
  cursorY: number
): number {
  const { page, helveticaBold, helvetica, formatCurrency, labels } = ctx;
  if (transactions.length === 0) return cursorY;
  let y = startNewPageIfNeeded(ctx, cursorY, 40);
  page.drawText(`${labels.transactions} (${transactions.length})`, {
    x: MARGIN_X,
    y: y - 12,
    size: 9,
    font: helveticaBold,
    color: COLOR_TEXT_SECONDARY,
  });
  y -= 18;

  const cols = {
    date: { x: MARGIN_X + 4, width: 64 },
    merchant: { x: MARGIN_X + 76, width: 150 },
    category: { x: MARGIN_X + 234, width: 110 },
    type: { x: MARGIN_X + 352, width: 50 },
    amount: { x: PAGE_WIDTH - MARGIN_X - 70, width: 66 },
  };

  const drawTableHeader = () => {
    const hy = y - 12;
    page.drawRectangle({
      x: MARGIN_X,
      y: hy - 8,
      width: PAGE_WIDTH - 2 * MARGIN_X,
      height: 20,
      color: COLOR_BG_SECONDARY,
    });
    page.drawText(labels.tableDate, {
      x: cols.date.x,
      y: hy,
      size: 8,
      font: helveticaBold,
      color: COLOR_TEXT_SECONDARY,
    });
    page.drawText(labels.tableMerchant, {
      x: cols.merchant.x,
      y: hy,
      size: 8,
      font: helveticaBold,
      color: COLOR_TEXT_SECONDARY,
    });
    page.drawText(labels.tableCategory, {
      x: cols.category.x,
      y: hy,
      size: 8,
      font: helveticaBold,
      color: COLOR_TEXT_SECONDARY,
    });
    page.drawText(labels.tableType, {
      x: cols.type.x,
      y: hy,
      size: 8,
      font: helveticaBold,
      color: COLOR_TEXT_SECONDARY,
    });
    page.drawText(labels.tableAmount, {
      x: cols.amount.x,
      y: hy,
      size: 8,
      font: helveticaBold,
      color: COLOR_TEXT_SECONDARY,
    });
  };

  drawTableHeader();
  y -= 22;

  for (const tx of transactions) {
    if (y - 18 < MARGIN_Y + 50) {
      ctx.page = ctx.pdf.addPage([PAGE_WIDTH, PAGE_HEIGHT]);
      ctx.pageNumber += 1;
      drawWatermark(ctx);
      drawHeaderBand(ctx);
      y = PAGE_HEIGHT - MARGIN_Y - 50;
      drawTableHeader();
      y -= 22;
    }
    const isIncome =
      tx.transactionType === "income" || tx.transactionType === "ingreso";
    const sign = isIncome ? "+" : "-";
    page.drawText(ctx.formatDate(tx.transactionDate), {
      x: cols.date.x,
      y: y - 8,
      size: 9,
      font: helvetica,
      color: COLOR_TEXT_SECONDARY,
    });
    const merchant = tx.name && tx.name.length > 0 ? tx.name : tx.merchant;
    page.drawText(truncate(helvetica, merchant, cols.merchant.width, 9), {
      x: cols.merchant.x,
      y: y - 8,
      size: 9,
      font: helvetica,
      color: COLOR_TEXT_PRIMARY,
    });
    page.drawText(tx.category, {
      x: cols.category.x,
      y: y - 8,
      size: 9,
      font: helvetica,
      color: COLOR_TEXT_SECONDARY,
    });
    page.drawText(sign, {
      x: cols.type.x,
      y: y - 8,
      size: 11,
      font: helveticaBold,
      color: isIncome ? COLOR_INCOME : COLOR_EXPENSE,
    });
    const amt = formatCurrency(tx.amount, tx.currency);
    page.drawText(amt, {
      x:
        cols.amount.x +
        cols.amount.width -
        helveticaBold.widthOfTextAtSize(amt, 9),
      y: y - 8,
      size: 9,
      font: helveticaBold,
      color: isIncome ? COLOR_INCOME : COLOR_EXPENSE,
    });
    y -= 18;
  }
  return y;
}

function drawFooter(ctx: PdfContext, _bottomY: number): void {
  const { page, helvetica, labels, pageNumber } = ctx;
  page.drawText(formatDateLocalized(new Date().toISOString(), ctx), {
    x: MARGIN_X,
    y: MARGIN_Y - 18,
    size: 8,
    font: helvetica,
    color: COLOR_TEXT_SECONDARY,
  });
  const pl = `${labels.pageLabel} ${pageNumber}`;
  page.drawText(pl, {
    x: PAGE_WIDTH - MARGIN_X - helvetica.widthOfTextAtSize(pl, 8),
    y: MARGIN_Y - 18,
    size: 8,
    font: helvetica,
    color: COLOR_TEXT_SECONDARY,
  });
  page.drawLine({
    start: { x: MARGIN_X, y: MARGIN_Y - 10 },
    end: { x: PAGE_WIDTH - MARGIN_X, y: MARGIN_Y - 10 },
    thickness: 0.5,
    color: COLOR_HEADER_RULE,
  });
}

// ─── helpers ──────────────────────────────────────────────────────────

interface PdfContext {
  pdf: PDFDocument;
  helvetica: PDFFont;
  helveticaBold: PDFFont;
  watermark: Awaited<ReturnType<PDFDocument["embedPng"]>> | null;
  labels: PdfLabel;
  formatCurrency: BuildReportPdfInput["formatCurrency"];
  formatDate: BuildReportPdfInput["formatDate"];
  page: ReturnType<PDFDocument["addPage"]>;
  pageNumber: number;
}

function formatDateRange(
  report: BuildReportPdfInput["report"],
  ctx: PdfContext
): string | null {
  const start = report.dateRangeStart
    ? ctx.formatDate(report.dateRangeStart)
    : null;
  const end = report.dateRangeEnd ? ctx.formatDate(report.dateRangeEnd) : null;
  if (!start && !end) return null;
  if (start && end) return `${start} \u2014 ${end}`;
  if (start) return `${start} \u2014`;
  return `\u2014 ${end}`;
}

function formatDateLocalized(iso: string, ctx: PdfContext): string {
  const lang = ctx.labels.reportLabel === "Reporte" ? "es" : "en-US";
  return new Intl.DateTimeFormat(lang, {
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  }).format(new Date(iso));
}

function startNewPageIfNeeded(
  ctx: PdfContext,
  y: number,
  needed: number
): number {
  if (y - needed < MARGIN_Y + 50) {
    ctx.page = ctx.pdf.addPage([PAGE_WIDTH, PAGE_HEIGHT]);
    ctx.pageNumber += 1;
    drawWatermark(ctx);
    drawHeaderBand(ctx);
    return PAGE_HEIGHT - MARGIN_Y - 50;
  }
  return y;
}

function wrapText(
  helvetica: PDFFont,
  text: string,
  maxWidth: number,
  size: number
): string[] {
  const words = text.split(/\s+/);
  const lines: string[] = [];
  let cur = "";
  for (const w of words) {
    const test = cur.length === 0 ? w : `${cur} ${w}`;
    if (helvetica.widthOfTextAtSize(test, size) > maxWidth && cur.length > 0) {
      lines.push(cur);
      cur = w;
    } else {
      cur = test;
    }
  }
  if (cur) lines.push(cur);
  return lines;
}

function truncate(
  helvetica: PDFFont,
  text: string,
  maxWidth: number,
  size: number
): string {
  if (helvetica.widthOfTextAtSize(text, size) <= maxWidth) return text;
  let trimmed = text;
  while (
    trimmed.length > 1 &&
    helvetica.widthOfTextAtSize(`${trimmed}\u2026`, size) > maxWidth
  ) {
    trimmed = trimmed.slice(0, -1);
  }
  return `${trimmed}\u2026`;
}
